#include <stdio.h>
#include <stdint.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N,M,X,Y; scanf("%lld %lld %lld %lld", &N, &M, &X, &Y);
        long long total = N * M;
        long long larger = (total + 1) / 2; // ceil
        long long smaller = total / 2;      // floor
        long long ans;
        if (2*X <= Y) {
            ans = total * X;
        } else {
            long long low = Y - X;
            if (low < 0) low = 0;
            ans = larger * X + smaller * low;
        }
        printf("%lld\n", ans);
    }
    return 0;
}

