#!/usr/bin/env python3
import sys
def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it)); M = int(next(it)); X = int(next(it)); Y = int(next(it))
        total = N * M
        larger = (total + 1) // 2  # ceil
        smaller = total // 2       # floor
        if 2 * X <= Y:
            ans = total * X
        else:
            low = Y - X
            if low < 0:
                low = 0
            ans = larger * X + smaller * low
        out.append(str(ans))
    sys.stdout.write('\n'.join(out))
if __name__ == "__main__":
    solve()

